package com.cho2hand.marketplace.service.impl.notification; import com.cho2hand.marketplace.dto.notification.NotificationResponse; import com.cho2hand.marketplace.entity.notification.Notification; import com.cho2hand.marketplace.exception.UserAccessDeniedException; import com.cho2hand.marketplace.repository.notification.NotificationRepository; import com.cho2hand.marketplace.service.notification.NotificationService; import java.util.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class NotificationServiceImpl implements NotificationService{private final NotificationRepository notifications;public NotificationServiceImpl(NotificationRepository n){notifications=n;}public void create(Long recipient,String type,String body,String path){var n=notifications.findFirstByRecipientUserIdAndTypeAndReferencePathAndReadAtIsNullOrderByCreatedAtDesc(recipient,type,path).orElseGet(Notification::new);n.setRecipientUserId(recipient);n.setType(type);n.setBody(body);n.setReferencePath(path);n.touch();notifications.save(n);} @Transactional(readOnly=true) public List<NotificationResponse> list(Long recipient){var seen=new HashSet<String>();return notifications.findByRecipientUserIdOrderByCreatedAtDesc(recipient).stream().filter(n->seen.add(n.getType()+"|"+n.getReferencePath())).map(this::response).toList();}public void read(Long recipient,Long id){var n=notifications.findById(id).filter(v->recipient.equals(v.getRecipientUserId())).orElseThrow(UserAccessDeniedException::new);notifications.findByRecipientUserIdAndTypeAndReferencePath(recipient,n.getType(),n.getReferencePath()).forEach(Notification::markRead);}private NotificationResponse response(Notification n){return new NotificationResponse(n.getId(),n.getType(),n.getBody(),n.getReferencePath(),n.getReadAt(),n.getCreatedAt());}}
